3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = { customer: Customer; steps: QuoteStep[] };
7	type StepResult = { premium: number };
8	type ScenarioResult = { results: StepResult[] };
9	
10	const BASE_PRICES: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const isCursed = (item: Item): boolean => item.cursed === true;
26	const isHighlyEnchanted = (item: Item): boolean =>
27	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
28	
29	const surchargeRate = (item: Item): number =>
30	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
31	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
32	
33	const itemSurchargeAmount = (item: Item): number =>
34	  basePriceOf(item) * surchargeRate(item);
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const BLOCK_SIZE = 3;
38	const BLOCK_PRICE = 60;
39	
40	const groupByType = (items: Item[]): Map<string, Item[]> =>
41	  items.reduce((groups, item) => {
42	    const existing = groups.get(item.type) ?? [];
43	    return groups.set(item.type, [...existing, item]);
44	  }, new Map<string, Item[]>());
45	
46	const groupBasePremium = (type: string, members: Item[]): number => {
47	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
48	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
49	};
50	
51	const itemsBaseSubtotal = (items: Item[]): number =>
52	  Array.from(groupByType(items)).reduce(
53	    (total, [type, members]) => total + groupBasePremium(type, members),
54	    0,
55	  );
56	
57	const itemsSurchargeSubtotal = (items: Item[]): number =>
58	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
59	
60	const LOYALTY_DISCOUNT_RATE = 0.2;
61	const LOYALTY_YEARS_THRESHOLD = 2;
62	
63	const isLoyalCustomer = (customer: Customer): boolean =>
64	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
65	
66	const loyaltyDiscountRate = (customer: Customer): number =>
67	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
68	
69	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
70	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
71	
72	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
73	
74	const followUpDiscountRate = (stepIndex: number): number =>
75	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
76	
77	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
78	  FIRST_INSURANCE_SURCHARGE_RATE -
79	  loyaltyDiscountRate(customer) -
80	  followUpDiscountRate(stepIndex);
81	
82	const quotePremium = (
83	  items: Item[],
84	  customer: Customer,
85	  stepIndex: number,
86	): number => {
87	  const baseSubtotal = itemsBaseSubtotal(items);
88	  const surchargeSubtotal = itemsSurchargeSubtotal(items);
89	  return (
90	    baseSubtotal +
91	    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
92	    surchargeSubtotal +
93	    PROCESSING_FEE
94	  );
95	};
96	
97	const runStep = (
98	  step: QuoteStep,
99	  customer: Customer,
100	  stepIndex: number,
101	): StepResult => ({
102	  premium: Math.ceil(quotePremium(step.items, customer, stepIndex)),
103	});
104	
105	export const runScenario = (input: Scenario): ScenarioResult => ({
106	  results: input.steps.map((step, i) => runStep(step, input.customer, i)),
107	});
